/**
 * n8n Function node
 * Extract hero <img> src, alt, and title from Gmail HTML.
 *
 * Input: items[0].json.html (string)
 * Output: { hero: { src, alt, title }, validations: {...}, raw: { imgTag, container } }
 */

function extractAttr(tag, attrName) {
  // Extracts attribute values from a tag string safely
  const re = new RegExp(`${attrName}\\s*=\\s*("([^"]*)"|'([^']*)'|([^\\s>]+))`, 'i');
  const m = tag.match(re);
  return m ? (m[2] || m[3] || m[4] || '') : '';
}

function firstImgTag(html) {
  // Find the hero container and the first <img> inside it

  // 1) Prefer a container with id="heroImage..."
  const heroDivMatch = html.match(
    /<div\s+class=["']mktoImg["']\s+id=["']heroImage[^"']*["'][\s\S]*?>[\s\S]*?<\/div>/i
  );
  if (heroDivMatch) {
    const heroDiv = heroDivMatch[0];
    const imgMatch = heroDiv.match(/<img\b[^>]*>/i);
    return { imgTag: imgMatch ? imgMatch[0] : '', container: heroDiv };
  }

  // 2) Fallback: module row with id starting "fullWidthImageModule"
  const moduleMatch = html.match(
    /<tr\s+class=["']mktoModule["']\s+id=["']fullWidthImageModule[^"']*["'][\s\S]*?>[\s\S]*?<\/tr>/i
  );
  if (moduleMatch) {
    const mod = moduleMatch[0];
    const imgMatch = mod.match(/<img\b[^>]*>/i);
    return { imgTag: imgMatch ? imgMatch[0] : '', container: mod };
  }

  // 3) Last resort: first centered hero-like <img> with max-width ~ 680
  const genericMatch = html.match(
    /<img\b[^>]*\b(max-width:\s*680px|width\s*=\s*["']680["'])[^>]*>/i
  );
  return { imgTag: genericMatch ? genericMatch[0] : '', container: '' };
}

const itemsOut = [];

for (const item of items) {
  const html = (item.json && item.json.html) ? item.json.html : '';

  if (!html || typeof html !== 'string') {
    itemsOut.push({
      json: {
        error: 'HTML content not found at items[0].json.html',
      },
    });
    continue;
  }

  const { imgTag, container } = firstImgTag(html);

  if (!imgTag) {
    itemsOut.push({
      json: {
        error: 'Hero image tag not found',
        hint: 'Ensure the hero block has id="heroImage..." or the module id starts with "fullWidthImageModule".',
      },
    });
    continue;
  }

  // Extract attributes
  const src = extractAttr(imgTag, 'src');
  const alt = extractAttr(imgTag, 'alt');
  const title = extractAttr(imgTag, 'title');

  // Minimal validations
  const validations = {
    hasSrc: Boolean(src),
    srcIsHttps: /^https:\/\//i.test(src),
    altPresent: alt.trim().length > 0,
    titlePresent: title.trim().length > 0,
    altTitleSame: alt.trim() && title.trim() ? alt.trim() === title.trim() : null,
  };

  itemsOut.push({
    json: {
      hero: { src, alt, title },
      validations,
      raw: { imgTag, container },
    },
  });
}

return itemsOut;

// Get all input items
const items = $input.all();

// Extract ParsedText from input1 and input2
const sourceAText = items[0]?.json?.ParsedResults?.[0]?.ParsedText || "";
const sourceBText = items[1]?.json?.ParsedResults?.[0]?.ParsedText || "";

// Normalize strings
function normalize(str) {
  return str.replace(/\s+/g, " ").trim().toLowerCase();
}

const normA = normalize(sourceAText);
const normB = normalize(sourceBText);

// Comparison logic
let result;
if (!normA && !normB) {
  result = "No content in either source";
} else if (!normA || !normB) {
  result = "Missing content in one source";
} else if (normA === normB) {
  result = "Exact Match";
} else if (normA.includes(normB) || normB.includes(normA)) {
  result = "Partial Match";
} else {
  result = "Mismatch";
}

// Return as columns
return [
  {
    "Column A (Source A Content)": sourceAText,
    "Column B (Source B Content)": sourceBText,
    "Column C (Result)": result
  }
];

